<h3 style="font-size:20px;font-weight:700;color:#0d1f2d;margin:0 0 6px">Saatke meile sonum</h3>
<p style="color:#6b8599;font-size:14px;margin:0 0 24px">Vastame 1 toopaeva jooksul.</p>
<form id="vesho-contact-form" style="display:flex;flex-direction:column;gap:16px" novalidate>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
    <div>
      <label style="display:block;font-size:13px;font-weight:600;color:#0d1f2d;margin-bottom:6px">Nimi *</label>
      <input name="name" type="text" required style="width:100%;padding:10px 14px;border:1.5px solid #dde4ea;border-radius:8px;font-size:14px;color:#0d1f2d;background:#fff;outline:none;box-sizing:border-box">
    </div>
    <div>
      <label style="display:block;font-size:13px;font-weight:600;color:#0d1f2d;margin-bottom:6px">Telefon *</label>
      <input name="phone" type="tel" required style="width:100%;padding:10px 14px;border:1.5px solid #dde4ea;border-radius:8px;font-size:14px;color:#0d1f2d;background:#fff;outline:none;box-sizing:border-box">
    </div>
  </div>
  <div>
    <label style="display:block;font-size:13px;font-weight:600;color:#0d1f2d;margin-bottom:6px">E-post</label>
    <input name="email" type="email" style="width:100%;padding:10px 14px;border:1.5px solid #dde4ea;border-radius:8px;font-size:14px;color:#0d1f2d;background:#fff;outline:none;box-sizing:border-box">
  </div>
  <div>
    <label style="display:block;font-size:13px;font-weight:600;color:#0d1f2d;margin-bottom:6px">Sonum *</label>
    <textarea name="message" required rows="5" style="width:100%;padding:10px 14px;border:1.5px solid #dde4ea;border-radius:8px;font-size:14px;color:#0d1f2d;background:#fff;outline:none;resize:vertical;box-sizing:border-box"></textarea>
  </div>
  <div id="contact-form-error" style="display:none;background:#fee2e2;color:#dc2626;padding:10px 14px;border-radius:8px;font-size:14px"></div>
  <div id="contact-form-success" style="display:none;background:#d1fae5;color:#065f46;padding:10px 14px;border-radius:8px;font-size:14px">Taname! Votame teiega peagi uhendust.</div>
  <button type="submit" id="contact-submit-btn" style="background:#00b4c8;color:#fff;border:none;border-radius:10px;padding:14px 28px;font-size:15px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:8px;justify-content:center">
    Saada sonum <span style="font-size:16px">&#8594;</span>
  </button>
</form>
</div>
<script>
(function(){
  var f=document.getElementById("vesho-contact-form");
  if(!f)return;
  f.addEventListener("submit",function(e){
    e.preventDefault();
    var err=document.getElementById("contact-form-error");
    var suc=document.getElementById("contact-form-success");
    var btn=document.getElementById("contact-submit-btn");
    err.style.display="none";suc.style.display="none";
    var name=f.querySelector("[name=name]").value.trim();
    var phone=f.querySelector("[name=phone]").value.trim();
    var msg=f.querySelector("[name=message]").value.trim();
    if(!name){err.textContent="Nimi on kohustuslik";err.style.display="block";return;}
    if(!phone){err.textContent="Telefon on kohustuslik";err.style.display="block";return;}
    if(!msg){err.textContent="Sonum on kohustuslik";err.style.display="block";return;}
    btn.disabled=true;btn.textContent="Saadan...";
    var fd=new FormData(f);
    fd.append("action","vesho_guest_request");
    fd.append("nonce",(window.VeshoData&&window.VeshoData.nonce)||"");
    fetch((window.VeshoData&&window.VeshoData.ajaxUrl)||"/wp-admin/admin-ajax.php",{method:"POST",body:fd})
    .then(function(r){return r.json();})
    .then(function(d){
      if(d.success){f.reset();suc.style.display="block";}
      else{err.textContent=(d.data&&d.data.message)||"Viga. Proovige uuesti.";err.style.display="block";}
      btn.disabled=false;btn.innerHTML="Saada sonum &#8594;";
    })
    .catch(function(){
      err.textContent="Uhenduse viga.";err.style.display="block";
      btn.disabled=false;btn.innerHTML="Saada sonum &#8594;";
    });
  });
})();
</script>"},"elements":[]}]}]}]
